static bool ValidityChecksL(const CRYPT_ML_DSA_Ctx *ctx, int32_t *const z[MLDSA_L_MAX], uint32_t t)
{
    bool valid = true;
    for (uint8_t i = 0; i < ctx->info->l; i++) {
        valid &= MLDSA_ValidityChecks(z[i], t);
    }
    return valid;
}
